<?php
namespace App\Http\Controllers\App;
use App\Http\Controllers\Controller; use App\Http\Requests\ServiceItemRequest; use App\Models\ServiceItem; use Illuminate\Http\Request;
class ServiceItemController extends Controller { public function index(Request $r){return response()->json($r->user()->serviceItems()->latest()->paginate());} public function store(ServiceItemRequest $r){return response()->json($r->user()->serviceItems()->create($r->validated()),201);} public function show(ServiceItem $serviceItem){$this->authorize('view',$serviceItem); return response()->json($serviceItem);} public function update(ServiceItemRequest $r, ServiceItem $serviceItem){$this->authorize('update',$serviceItem); $serviceItem->update($r->validated()); return response()->json($serviceItem);} public function destroy(ServiceItem $serviceItem){$this->authorize('delete',$serviceItem); $serviceItem->delete(); return response()->noContent();}}
